example.code:
scalar DateTime
scalar UUID
scalar Email

interface Node { id: ID! }
interface Timestamped { createdAt: DateTime!; updatedAt: DateTime! }

enum UserRole { ADMIN MODERATOR MEMBER }

type User implements Node & Timestamped {
  id: ID!
  email: Email!
  name: String!
  role: UserRole!
  isActive: Boolean!
  createdAt: DateTime!
  updatedAt: DateTime!
  orders(first: Int, after: String): OrderConnection!
}

type CreateUserPayload {
  user: User
  errors: [UserError!]
}

type UserError {
  field: String
  message: String!
  code: String!  # stable enum: VALIDATION_ERROR, EMAIL_TAKEN, etc.
}

type Mutation {
  createUser(input: CreateUserInput!): CreateUserPayload!
}
